// Literal (most common)
const fruits = ['apple', 'banana', 'cherry'];

// Array constructor — only use when you need a sized sparse array
const slots = new Array(5);        // [empty × 5]  (5 empty slots, not 5 undefineds)

// Array.from — create from any iterable or array-like
const digits = Array.from({ length: 5 }, (_, i) => i); // [0, 1, 2, 3, 4]
const chars  = Array.from('hello');                      // ['h','e','l','l','o']
const unique = Array.from(new Set([1, 2, 2, 3]));        // [1, 2, 3]

// Array.of — fixes the one-argument quirk of Array constructor
Array.of(7);    // [7]  (not [empty × 7])

const arr = [1, 2, 3];

// End
arr.push(4, 5);    // arr = [1,2,3,4,5]; returns new length (5)
arr.pop();         // arr = [1,2,3,4];  returns removed value (5)

// Start
arr.unshift(0);    // arr = [0,1,2,3,4]; returns new length (5)
arr.shift();       // arr = [1,2,3,4];   returns removed value (0)

const arr = ['a', 'b', 'c', 'd'];

// splice(start, deleteCount, ...items)
arr.splice(1, 2);             // removes 2 from index 1 → ['a','d']; returns ['b','c']
arr.splice(1, 0, 'x', 'y');  // inserts at index 1     → ['a','x','y','d']
arr.splice(2, 1, 'z');        // replaces 1 at index 2  → ['a','x','z','d']

// sort mutates in place — default converts to strings
[10, 9, 2, 1].sort();                    // [1, 10, 2, 9]  ← string order (wrong for numbers)
[10, 9, 2, 1].sort((a, b) => a - b);    // [1, 2, 9, 10]  ← numeric ascending

const names = ['Charlie', 'Alice', 'Bob'];
names.sort();                             // ['Alice', 'Bob', 'Charlie']

// Always spread to avoid mutation:
