const nested = [[1, 2], [3, [4, 5]]];
nested.flat();     // [1, 2, 3, [4, 5]]  (1 level)
nested.flat(2);    // [1, 2, 3, 4, 5]   (2 levels)
nested.flat(Infinity);  // fully flatten

// flatMap = map + 1-level flat (more efficient than separate calls)
const sentences = ['hello world', 'foo bar'];
const words = sentences.flatMap(s => s.split(' '));
// ['hello', 'world', 'foo', 'bar']

// Expand each item into multiple rows
const cart = [{ name: 'A', qty: 2 }, { name: 'B', qty: 3 }];
const rows = cart.flatMap(item =>
  Array.from({ length: item.qty }, () => item.name)
);
// ['A', 'A', 'B', 'B', 'B']

const users = [
  { id: 1, name: 'Alice', score: 92 },
