const arr = [1, 2, 3, 4, 5];

// slice(start, end) — non-mutating, end is exclusive
arr.slice(1, 3);     // [2, 3]
arr.slice(-2);       // [4, 5]  (last 2)
arr.slice();         // [1,2,3,4,5]  (shallow copy)

// concat — join arrays
[1, 2].concat([3, 4], [5]);  // [1, 2, 3, 4, 5]
// spread equivalent:
[...[1,2], ...[3,4], 5];

// join — array to string
['2025', '06', '30'].join('-');  // '2025-06-30'

// split — string to array (String method, returns array)
'a,b,c'.split(',');  // ['a', 'b', 'c']

@Component({ ... })
export class TodoListComponent {
  todos = signal<Todo[]>([]);

  addTodo(text: string) {
    this.todos.update(current => [...current, { id: Date.now(), text, done: false }]);
  }

  removeTodo(id: number) {
    this.todos.update(current => current.filter(t => t.id !== id));
  }

  toggleTodo(id: number) {
    this.todos.update(current =>
      current.map(t => t.id === id ? { ...t, done: !t.done } : t)
    );
  }

  completedCount = computed(() => this.todos().filter(t => t.done).length);
}

trackById(_index: number, item: { id: number }) {
  return item.id;
}

@Component({ ... })
export class ProductListComponent {
  private all = signal<Product[]>([]);
  search = signal('');
  sortKey = signal<keyof Product>('name');

  // computed filters + sorts without mutating `all`
  displayed = computed(() => {
    const q = this.search().toLowerCase();
    return [...this.all()]
      .filter(p => p.name.toLowerCase().includes(q))
      .sort((a, b) => String(a[this.sortKey()]).localeCompare(String(b[this.sortKey()])));
  });
}

